        updateContributors(new ArrayList<>());
        return 0;
    } else {
        System.out.println("Found " + repos.size() + " repositories in " + org + " organization.");
    }

    // Create thread pool for parallel API requests
    ExecutorService executor = Executors.newFixedThreadPool(Math.min(repos.size(), 10));

